INSERT INTO public.system_changelog (version, title, description, category) VALUES ('3.30.0', 'Hierarquia de marca e páginas legais no layout', 'Login passa a exibir o logo Gente Networking (marca do negócio) com o título "Gente Comunidade" (produto). Termos de Uso, Política de Privacidade e Política de Cookies foram movidas para dentro do layout autenticado da plataforma. E-mails já utilizavam o logo Gente Networking.', 'ui');